namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new Recipe
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices.", "Dice tomatoes and mix with garlic, basil, and olive oil.", "Spoon mixture onto toast and serve."],
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
            Steps = ["Remove mushroom stems.", "Mix cream cheese, garlic, parsley, and breadcrumbs.", "Fill caps and bake at 375°F for 20 minutes."],
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente.", "Fry pancetta until crispy.", "Whisk eggs with Parmesan.", "Toss hot pasta with pancetta, then stir in egg mixture off heat."],
            AverageRating = 4.8, RatingCount = 25
        },
        new Recipe
        {
            Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Yogurt", "Tomato sauce", "Cream", "Garam masala", "Cumin"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill chicken pieces.", "Simmer tomato sauce with cream and spices.", "Add chicken to sauce and serve with rice."],
            AverageRating = 4.7, RatingCount = 18
        },
        new Recipe
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter together.", "Whisk eggs and sugar until fluffy.", "Fold in chocolate mixture and flour.", "Bake at 425°F for 12 minutes."],
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs", "Sugar"],
            Steps = ["Dip ladyfingers in espresso.", "Whisk egg yolks with sugar, fold in mascarpone.", "Layer soaked ladyfingers and cream.", "Refrigerate 4 hours, dust with cocoa."],
            AverageRating = 4.6, RatingCount = 15
        },
        new Recipe
        {
            Id = 7, Title = "Mango Lassi", Category = "Beverages", CategorySlug = "beverages",
            Ingredients = ["Mango", "Yogurt", "Milk", "Sugar", "Cardamom"],
            Steps = ["Blend mango, yogurt, milk, sugar, and cardamom until smooth.", "Serve chilled."],
            AverageRating = 4.3, RatingCount = 10
        },
        new Recipe
        {
            Id = 8, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking",
            Ingredients = ["Bread flour", "Water", "Sourdough starter", "Salt"],
            Steps = ["Mix flour, water, and starter. Rest 30 minutes.", "Add salt and fold dough every 30 minutes for 3 hours.", "Shape and proof overnight in fridge.", "Bake in Dutch oven at 450°F for 45 minutes."],
            AverageRating = 4.4, RatingCount = 20
        },
        new Recipe
        {
            Id = 9, Title = "Vegetable Stir Fry", Category = "Vegetarian", CategorySlug = "vegetarian",
            Ingredients = ["Broccoli", "Bell peppers", "Tofu", "Soy sauce", "Ginger", "Garlic", "Sesame oil"],
            Steps = ["Press and cube tofu, pan-fry until golden.", "Stir-fry vegetables with ginger and garlic.", "Add tofu and soy sauce, toss to combine.", "Serve over rice."],
            AverageRating = 4.1, RatingCount = 14
        },
        new Recipe
        {
            Id = 10, Title = "Eggplant Parmesan", Category = "Vegetarian", CategorySlug = "vegetarian",
            Ingredients = ["Eggplant", "Marinara sauce", "Mozzarella", "Parmesan", "Breadcrumbs", "Eggs"],
            Steps = ["Slice and salt eggplant, let drain 30 minutes.", "Bread slices with egg and breadcrumbs, fry until golden.", "Layer with marinara and cheese in baking dish.", "Bake at 375°F for 25 minutes."],
            AverageRating = 4.5, RatingCount = 11
        }
    ];

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public string GetCategoryName(string slug)
    {
        return _recipes.FirstOrDefault(r => r.CategorySlug == slug)?.Category ?? slug;
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = (totalStars + stars) / recipe.RatingCount;
    }
}

