        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverRating = star"
                  @onmouseout="() => hoverRating = 0"
                  class="@(star <= (hoverRating > 0 ? hoverRating : selectedRating) ? "text-warning" : "text-muted")">
                ★
            </span>
        }
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-2" role="alert">
            Thanks! You rated this recipe @selectedRating star@(selectedRating != 1 ? "s" : "").
        </div>
    }

    <small class="text-muted">
        Average: @AverageRating.ToString("F1") / 5 (@RatingCount ratings)
    </small>
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double AverageRating { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }

        submitted = true;
    }
}

