+@using RecipeShare.Services
+@inject RecipeService RecipeService
+@rendermode InteractiveServer
+
+<div class="my-3 p-3 border rounded">
+    <h5>Rate this recipe</h5>
+    <div class="star-rating" style="font-size: 1.5rem; cursor: pointer;">
+        @for (int i = 1; i <= 5; i++)
+        {
+            var star = i;
+            <span @onclick="() => SubmitRating(star)"
+                  @onmouseover="() => hoverRating = star"
+                  @onmouseout="() => hoverRating = 0"
+                  class="@(star <= (hoverRating > 0 ? hoverRating : selectedRating) ? "text-warning" : "text-muted")">
+                ★
+            </span>
+        }
+    </div>
+
+    @if (submitted)
+    {
+        <div class="alert alert-success mt-2" role="alert">
+            Thanks! You rated this recipe @selectedRating star@(selectedRating != 1 ? "s" : "").
+        </div>
+    }
+
+    <small class="text-muted">
+        Average: @AverageRating.ToString("F1") / 5 (@RatingCount ratings)
+    </small>
+</div>
+
+@code {
+    [Parameter]
+    public int RecipeId { get; set; }
+
+    [Parameter]
+    public double AverageRating { get; set; }
+
+    [Parameter]
+    public int RatingCount { get; set; }
+
+    private int hoverRating;
+    private int selectedRating;
+    private bool submitted;
+
+    private void SubmitRating(int stars)
+    {
+        selectedRating = stars;
+        RecipeService.AddRating(RecipeId, stars);
+
+        var recipe = RecipeService.GetById(RecipeId);
+        if (recipe is not null)
+        {
+            AverageRating = recipe.AverageRating;
+            RatingCount = recipe.RatingCount;
+        }
+
+        submitted = true;
+    }
+}
+

toolArgs.file_text:
@page "/submit"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success" role="alert">
        @successMessage
    </div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="appetizers">Appetizers</option>
            <option value="main-courses">Main Courses</option>
            <option value="desserts">Desserts</option>
            <option value="beverages">Beverages</option>
            <option value="baking">Baking</option>
            <option value="vegetarian">Vegetarian</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="5"
                       placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
        <ValidationMessage For="() => model.Ingredients" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
        <ValidationMessage For="() => model.Steps" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private static readonly Dictionary<string, string> CategoryNames = new()
    {
        ["appetizers"] = "Appetizers",
        ["main-courses"] = "Main Courses",
        ["desserts"] = "Desserts",
        ["beverages"] = "Beverages",
        ["baking"] = "Baking",
        ["vegetarian"] = "Vegetarian"
    };

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = model.Title,
            CategorySlug = model.Category,
            Category = CategoryNames.GetValueOrDefault(model.Category, model.Category),
            Ingredients = model.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = model.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        successMessage = $"Recipe \"{recipe.Title}\" submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string Steps { get; set; } = string.Empty;
    }
}

